Replace the contents of backend/access-control.mo with exactly the following code provided by the user:

```
import Map "mo:core/Map";
import Principal "mo:core/Principal";
import Runtime "mo:core/Runtime";

module {
  // Hardcoded owner principal — always has admin role regardless of token
  let OWNER_PRINCIPAL : Principal =
Principal.fromText("gyojt-gsv7l-g3oqx-3m7xb-w7cmh-nck6r-so6sn-fc7jp-ymofr-fgq6n-eae");

  public type UserRole = {
    #admin;
    #user;
    #guest;
  };

  public type AccessControlState = {
    var adminAssigned : Bool;
    userRoles : Map.Map<Principal, UserRole>;
  };

  public func initState() : AccessControlState {
    {
      var adminAssigned = false;
      userRoles = Map.empty<Principal, UserRole>();
    };
  };

  public func initialize(state : AccessControlState, caller : Principal, adminToken :
Text, userProvidedToken : Text) {
    if (caller.isAnonymous()) { return };
    switch (state.userRoles.get(caller)) {
      case (?_) {};
      case (null) {
        if (caller == OWNER_PRINCIPAL) {
          state.userRoles.add(caller, #admin);
          state.adminAssigned := true;
        } else if (not state.adminAssigned and userProvidedToken == adminToken) {
          state.userRoles.add(caller, #admin);
          state.adminAssigned := true;
        } else {
          state.userRoles.add(caller, #user);
        };
      };
    };
  };

  public func getUserRole(state : AccessControlState, caller : Principal) : UserRole {
    if (caller.isAnonymous()) { return #guest };
    if (caller == OWNER_PRINCIPAL) { return #admin };
    switch (state.userRoles.get(caller)) {
      case (?role) { role };
      case (null) {
        Runtime.trap("User is not registered");
      };
    };
  };

  public func assignRole(state : AccessControlState, caller : Principal, user :
Principal, role : UserRole) {
    if (not (isAdmin(state, caller))) {
      Runtime.trap("Unauthorized: Only admins can assign user roles");
    };
    state.userRoles.add(user, role);
  };

  public func hasPermission(state : AccessControlState, caller : Principal,
requiredRole : UserRole) : Bool {
    if (caller == OWNER_PRINCIPAL) { return true };
    let userRole = getUserRole(state, caller);
    if (userRole == #admin or requiredRole == #guest) { true } else { userRole ==
requiredRole };
  };

  public func isAdmin(state : AccessControlState, caller : Principal) : Bool {
    if (caller == OWNER_PRINCIPAL) { return true };
    getUserRole(state, caller) == #admin;
  };
};
```

The key changes from the previous version are:
- `getUserRole` now returns `#admin` immediately for `OWNER_PRINCIPAL` before checking the userRoles map, so the owner always receives the admin role even if not yet registered.
- `hasPermission` now returns `true` immediately for `OWNER_PRINCIPAL` before any other role checks.
- `isAdmin` continues to short-circuit for `OWNER_PRINCIPAL` as before.
- The hardcoded owner principal is `gyojt-gsv7l-g3oqx-3m7xb-w7cmh-nck6r-so6sn-fc7jp-ymofr-fgq6n-eae`.
